import{c as a,Q as e,j as n,m as i}from"./chunks/framework.iD28w_5a.js";const k=JSON.parse('{"title":"Syscall GP Fault","description":"","frontmatter":{"title":"Syscall GP Fault"},"headers":[],"relativePath":"notes/028b/syscall_gp_fault.md","filePath":"notes/028b/syscall_gp_fault.md","lastUpdated":1779686691000}'),l={name:"notes/028b/syscall_gp_fault.md"};function p(t,s,r,d,c,h){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="syscall-gp-fault-排查报告" tabindex="-1">syscall GP Fault 排查报告 <a class="header-anchor" href="#syscall-gp-fault-排查报告" aria-label="Permalink to &quot;syscall GP Fault 排查报告&quot;">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>在 QEMU 中执行 <code>touch /hello2.txt</code> 时触发 General Protection Fault：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>==== EXCEPTION: #GP (vector 13) ====</span></span>
<span class="line"><span>  RIP   = 0xFFFFFFFF81005D97   CS  = 0x0010</span></span>
<span class="line"><span>  RFLAGS= 0x0000000000010002</span></span>
<span class="line"><span>  ERROR CODE = 0x0000000000000000</span></span>
<span class="line"><span>========================================</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="定位过程" tabindex="-1">定位过程 <a class="header-anchor" href="#定位过程" aria-label="Permalink to &quot;定位过程&quot;">​</a></h2><h3 id="_1-确定崩溃函数" tabindex="-1">1. 确定崩溃函数 <a class="header-anchor" href="#_1-确定崩溃函数" aria-label="Permalink to &quot;1. 确定崩溃函数&quot;">​</a></h3><p>通过 <code>nm</code> 反查崩溃地址：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ffffffff81005d20 T Ext2::create(uint32_t, char const*, uint32_t)</span></span>
<span class="line"><span>ffffffff81005e90 T Ext2DirOps::create(Inode*, char const*, uint32_t)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>RIP=0x5D97 落在 <code>Ext2::create()</code> 内部。</p><h3 id="_2-反汇编定位崩溃指令" tabindex="-1">2. 反汇编定位崩溃指令 <a class="header-anchor" href="#_2-反汇编定位崩溃指令" aria-label="Permalink to &quot;2. 反汇编定位崩溃指令&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ffffffff81005d7d:  lea    0x80(%rsp),%rdx    ; new_disk 栈变量地址</span></span>
<span class="line"><span>ffffffff81005d8e:  mov    %rdx,%rax</span></span>
<span class="line"><span>ffffffff81005d97:  movaps %xmm0,(%rax)       ; ← GP fault 在这里</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>movaps</code> 要求 16 字节对齐。RAX = RSP + 0x80 = 0x...D78，0x78 % 16 = 8，未对齐。</p><h3 id="_3-根因分析" tabindex="-1">3. 根因分析 <a class="header-anchor" href="#_3-根因分析" aria-label="Permalink to &quot;3. 根因分析&quot;">​</a></h3><p>崩溃根因是 <strong>syscall 入口未保证 16 字节栈对齐</strong>。</p><p>调用链：<code>syscall_entry (asm)</code> → <code>syscall_dispatch (C)</code> → ... → <code>Ext2::create (C)</code></p><p><code>syscall_entry</code> 中 push 了 12 个寄存器构建 trap frame（96 字节），再 push 第 7 个 C 参数（8 字节），共 13 次 push = 104 字节。104 % 16 = 8，导致 <code>call syscall_dispatch</code> 前 RSP 不是 16 的倍数。</p><p>SysV AMD64 ABI 要求：<code>call</code> 指令前 RSP 必须是 16 字节对齐的。由于差了 8 字节，后续所有函数的栈布局都偏移了 8 字节。当编译器生成 SSE <code>movaps</code>（要求 16 字节对齐）来零初始化栈上的 <code>Ext2Inode</code> 结构体时，触发 GP fault。</p><h3 id="_4-为什么之前的-syscall-没有崩溃" tabindex="-1">4. 为什么之前的 syscall 没有崩溃 <a class="header-anchor" href="#_4-为什么之前的-syscall-没有崩溃" aria-label="Permalink to &quot;4. 为什么之前的 syscall 没有崩溃&quot;">​</a></h3><p>此前已注册的 syscall（<code>sys_read</code>、<code>sys_write</code>、<code>sys_open</code> 等）在执行路径上恰好没有触发 SSE 对齐指令。<code>sys_creat</code> 是第一个深入调用 ext2 复杂逻辑的 syscall，其中 <code>Ext2::create()</code> 用循环清零 <code>Ext2Inode</code>（编译器优化为 <code>movaps</code>），才首次暴露了这个问题。</p><h2 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h2><p>在 <code>kernel/arch/x86_64/syscall.S</code> 中，push 第 7 个参数前加 <code>subq $8, %rsp</code> 对齐栈：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 72</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # load a6</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    subq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # ← 新增：16 字节对齐</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pushq %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                         # push 7th arg</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 40</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rdi</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # offsets +8 (now +16 due to padding)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ...</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> syscall_dispatch</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addq </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # remove arg + padding (was $8)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>修复后所有偏移量从 +8 调整为 +16（多了一层 padding），清理时 <code>addq</code> 从 $8 改为 $16。</p><h2 id="教训" tabindex="-1">教训 <a class="header-anchor" href="#教训" aria-label="Permalink to &quot;教训&quot;">​</a></h2><ol><li><p><strong>syscall/中断入口的栈对齐是硬性要求</strong>：x86_64 SysV ABI 假定 <code>call</code> 前 RSP 是 16 的倍数。任何手写汇编入口（syscall、interrupt handler）都必须维护这个不变量，否则所有使用 SSE 指令的编译代码都可能随机崩溃。</p></li><li><p><strong>对齐 bug 有隐蔽性</strong>：bug 不在崩溃函数中，而在调用链最顶层的汇编入口中。简单的 syscall（浅调用栈）不会触发，只有深入调用且碰上 SSE 指令时才暴露。</p></li><li><p><strong>排查方法</strong>：GP fault + error_code=0 → 先看是否为对齐问题；反汇编确认 <code>movaps</code>/<code>movdqa</code> 等对齐指令；回溯栈布局计算 RSP 对齐状态。</p></li></ol>`,25)])])}const u=a(l,[["render",p]]);export{k as __pageData,u as default};
